     1→#!/usr/bin/env node
     2→/**
     3→ * Send a message to an A2A peer using the official @a2a-js/sdk.
     4→ *
     5→ * Usage:
     6→ *   node a2a-send.mjs --peer-url <PEER_BASE_URL> --token <TOKEN> --message "Hello!"
     7→ *   node a2a-send.mjs --peer-url http://100.76.43.74:18800 --token abc123 --message "What is your name?"
     8→ *   node a2a-send.mjs --peer-url <URL> --token <TOKEN> --message "Follow up" --task-id <TASK_ID> --context-id <CONTEXT_ID>
     9→ *
    10→ * Async task mode (recommended for long-running prompts):
    11→ *   node a2a-send.mjs --peer-url <URL> --token <TOKEN> --non-blocking --wait --message "..."
    12→ *
    13→ * Options:
    14→ *   --peer-url <url>        Peer base URL, e.g. http://100.76.43.74:18800
    15→ *   --token <token>         Bearer token for the peer inbound auth
    16→ *   --message <text>        Text to send
    17→ *   --task-id <id>          Reuse an existing A2A task for follow-up turns
    18→ *   --context-id <id>       Reuse an existing A2A context for multi-round conversation routing
    19→ *   --non-blocking          Send with configuration.blocking=false (returns quickly with a Task)
    20→ *   --wait                  When non-blocking, poll tasks/get until terminal state
    21→ *   --timeout-ms <ms>       Max wait time for --wait (default: 600000)
    22→ *   --poll-ms <ms>          Poll interval for --wait (default: 1000)
    23→ *   --help                  Show this help text
    24→ *
    25→ * Optional (OpenClaw extension):
    26→ *   --agent-id <agentId>    Route the inbound A2A request to a specific OpenClaw agentId on the peer.
    27→ *                           Note: this works reliably over JSON-RPC/REST. gRPC transport may drop unknown
    28→ *                           Message fields, so gRPC is disabled when --agent-id is used.
    29→ *
    30→ * Requires: npm install @a2a-js/sdk
    31→ */
    32→
